int nextIndexOf(CharSequence seq) {
    if (seq == null || seq.length() == 0)
        return -1;

    char startChar = seq.charAt(0);
    for (int offset = pos; offset <= length - seq.length(); offset++) {
        // scan to first instance of startchar:
        if (input[offset] == startChar) {
            int i = offset + 1;
            int last = offset + seq.length();
            boolean match = true;
            for (int j = 1; i < last; i++, j++) {
                if (seq.charAt(j) != input[i]) {
                    match = false;
                    break;
                }
            }
            if (match) // found full sequence
                return offset - pos;
        }
    }
    return -1;
}

int nextIndexOf(CharSequence seq) {
    if (seq == null || seq.length() == 0) return -1;
    char startChar = seq.charAt(0);
    int seqLength = seq.length();
    for (int offset = pos; offset <= length - seqLength; offset++) {
        if (input[offset] == startChar) {
            boolean match = true;
            for (int j = 1; j < seqLength; j++) {
                if (offset + j >= length || seq.charAt(j) != input[offset + j]) {
                    match = false;
                    break;
                }
            }
            if (match) return offset - pos;
        }
        // Handle surrogate pairs
        if (Character.isHighSurrogate(input[offset])) {
            offset++; // Skip the low surrogate
        }
    }
    return -1;
}
